    private StateRegistry() {}

    public static State create(final Game game, final StateConstructorLock lock) {
        if (useFullStateOnly) return new FullState(game, lock);
        final BiFunction<Game, StateConstructorLock, State> factory = FACTORIES.get(game.name());
        return factory != null ? factory.apply(game, lock) : new FullState(game, lock);
    }
